// Filter for markets closing within 24 hours and detect newly closing ones
const markets = $input.all();
const now = Date.now();
const WINDOW_MS = 24 * 60 * 60 * 1000; // 24 hours
const cutoff = now + WINDOW_MS;

// Access workflow static data to track previously seen closing markets
const staticData = $getWorkflowStaticData('global');
const previouslyClosing = new Set(staticData.closingMarketIds || []);

// Find markets closing within the window
const closingSoon = [];
for (const item of markets) {
  const m = item.json;
  const endDate = m.endDate || m.expirationDate || m.endDateIso || m.end_date_iso;
  if (!endDate) continue;

  const endTime = new Date(endDate).getTime();
  if (isNaN(endTime)) continue;

  // Market must be closing in the future but within our window
  if (endTime > now && endTime <= cutoff) {
    // Parse current prices
    let outcomePrices = m.outcomePrices || [];
    if (typeof outcomePrices === 'string') {
      try { outcomePrices = JSON.parse(outcomePrices); } catch(e) { outcomePrices = []; }
    }

    let outcomes = m.outcomes || [];
    if (typeof outcomes === 'string') {
      try { outcomes = JSON.parse(outcomes); } catch(e) { outcomes = []; }
    }

    const hoursLeft = ((endTime - now) / (60 * 60 * 1000)).toFixed(1);
    const yesPrice = Number(outcomePrices[0] || 0).toFixed(3);

    closingSoon.push({
      conditionId: m.conditionId || '',
      question: m.question || 'Unknown',
      slug: m.slug || '',
      endDate,
      hoursLeft,
      yesPrice,
      volume: Number(m.volume || 0)
    });
  }
}

// Find markets that are NEW to the closing window
const currentClosingIds = new Set(closingSoon.map(m => m.conditionId));
const newlyClosing = closingSoon.filter(m => !previouslyClosing.has(m.conditionId));

// Update static data for next run
staticData.closingMarketIds = Array.from(currentClosingIds);

if (newlyClosing.length === 0) {
  return [{ json: { _noNew: true } }];
}

// Format alert message
let message = `Markets resolving within 24 hours:\n\n`;
for (const m of newlyClosing) {
  message += `${m.question}\n  YES: $${m.yesPrice} | ${m.hoursLeft}h left | Vol: $${Number(m.volume).toLocaleString()}\n  https://polymarket.com/event/${m.slug}\n\n`;
}
message += `${newlyClosing.length} market(s) entering resolution window.`;

return [{
  json: {
    message,
    count: newlyClosing.length,
    markets: newlyClosing,
    _noNew: false
  }
}];
